CREATE TABLE he_luo_lookup (
    id          SERIAL PRIMARY KEY,
    matrix_code VARCHAR(32) NOT NULL,
    row_key     VARCHAR(4) NOT NULL,
    col_key     VARCHAR(4) NOT NULL,
    value       SMALLINT NOT NULL CHECK (value >= 0 AND value <= 9),
    UNIQUE (matrix_code, row_key, col_key)
);

CREATE INDEX idx_he_luo_lookup_matrix ON he_luo_lookup (matrix_code);

-- 河图查表：row_key=地支, col_key=天干
